// DevotionalLibrary.swift
// 365 daily devotionals for Global Brotherhood circle

import Foundation

struct DevotionalLibrary {

    static func devotionalForToday() -> String {
        let dayOfYear = max(1, Calendar.current.ordinality(of: .day, in: .year, for: Date()) ?? 1)
        return dailyDevotionals[(dayOfYear - 1) % dailyDevotionals.count]
    }

    static let dailyDevotionals: [String] = [
        "\"Be watchful, stand firm in the faith, act like men, be strong.\" \u{2014} 1 Corinthians 16:13\n\nWhat does it mean to stand firm today? Not just surviving, but actively rooting yourself in truth. Share your honest response with the brotherhood today.",
        "\"Iron sharpens iron, and one man sharpens another.\" \u{2014} Proverbs 27:17\n\nWho is sharpening you right now? If the answer is no one, reach out to a brother today. How does this truth change the way you approach today?",
        "\"The Lord is my shepherd; I shall not want.\" \u{2014} Psalm 23:1\n\nWhat are you trying to provide for yourself that only God can give? What would it look like to live this out in the next 24 hours?",
        "\"Watch and pray so that you will not fall into temptation.\" \u{2014} Matthew 26:41\n\nJesus said watch AND pray. Not try harder. What are you watching for today? Today, challenge: share this with one person who needs to hear it.",
